const express = require('express');
const redis = require('redis');
const crypto = require('crypto');
const { createServer } = require('https');
const fs = require('fs');
const path = require('path');

const app = express();
app.use(express.json());

const redisClient = redis.createClient({
  host: process.env.REDIS_HOST || 'localhost',
  port: process.env.REDIS_PORT || 6379,
  password: process.env.REDIS_PASSWORD,
  tls: process.env.REDIS_TLS === 'true' ? {} : undefined
});

redisClient.on('error', (err) => {
  console.error('Redis error:', err);
});

const CLIENTS = new Map([
  ['client1', { secret: process.env.CLIENT_SECRET || 'client1secret' }],
  ['client2', { secret: process.env.CLIENT_SECRET2 || 'client2secret' }]
]);

const USERS = new Map([
  ['user1', { password: process.env.USER_PASSWORD || 'user1pass' }],
  ['user2', { password: process.env.USER_PASSWORD2 || 'user2pass' }]
]);

const generateToken = () => {
  return crypto.randomBytes(32).toString('hex');
};

const validateClient = (clientId, clientSecret) => {
  const client = CLIENTS.get(clientId);
  if (!client) return false;
  return crypto.timingSafeEqual(
    Buffer.from(client.secret),
    Buffer.from(clientSecret)
  );
};

const validateUser = (username, password) => {
  const user = USERS.get(username);
  if (!user) return false;
  return crypto.timingSafeEqual(
    Buffer.from(user.password),
    Buffer.from(password)
  );
};

const validateScopes = (requestedScopes, allowedScopes) => {
  return requestedScopes.every(scope => allowedScopes.includes(scope));
};

app.post('/oauth/token', async (req, res) => {
  try {
    const { grant_type, client_id, client_secret, username, password, scope, refresh_token } = req.body;

    if (!validateClient(client_id, client_secret)) {
      return res.status(401).json({ error: 'invalid_client' });
    }

    if (grant_type === 'password') {
      if (!validateUser(username, password)) {
        return res.status(401).json({ error: 'invalid_grant' });
      }

      const accessToken = generateToken();
      const refreshToken = generateToken();

      const tokenData = {
        user_id: username,
        client_id: client_id,
        scopes: scope ? scope.split(' ') : ['read'],
        created_at: Date.now()
      };

      await redisClient.setex(`access:${accessToken}`, 3600, JSON.stringify(tokenData));
      await redisClient.setex(`refresh:${refreshToken}`, 31536000, JSON.stringify(tokenData));

      return res.json({
        access_token: accessToken,
        token_type: 'Bearer',
        expires_in: 3600,
        refresh_token: refreshToken
      });
    }

    if (grant_type === 'refresh_token') {
      if (!refresh_token) {
        return res.status(400).json({ error: 'invalid_request' });
      }

      const tokenData = await redisClient.get(`refresh:${refresh_token}`);
      if (!tokenData) {
        return res.status(400).json({ error: 'invalid_grant' });
      }

      const data = JSON.parse(tokenData);
      const accessToken = generateToken();

      await redisClient.setex(`access:${accessToken}`, 3600, JSON.stringify(data));

      return res.json({
        access_token: accessToken,
        token_type: 'Bearer',
        expires_in: 3600,
        refresh_token: refresh_token
      });
    }

    return res.status(400).json({ error: 'unsupported_grant_type' });
  } catch (error) {
    console.error('Token error:', error);
    res.status(500).json({ error: 'server_error' });
  }
});

app.get('/oauth/authorize', (req, res) => {
  const { response_type, client_id, redirect_uri, scope, state } = req.query;

  if (response_type !== 'code') {
    return res.status(400).json({ error: 'unsupported_response_type' });
  }

  if (!client_id || !redirect_uri) {
    return res.status(400).json({ error: 'invalid_request' });
  }

  const client = CLIENTS.get(client_id);
  if (!client) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  const authCode = generateToken();
  const codeData = {
    client_id: client_id,
    redirect_uri: redirect_uri,
    scopes: scope ? scope.split(' ') : ['read'],
    state: state,
    created_at: Date.now()
  };

  redisClient.setex(`auth:${authCode}`, 300, JSON.stringify(codeData));

  const redirectUrl = new URL(redirect_uri);
  redirectUrl.searchParams.append('code', authCode);
  if (state) redirectUrl.searchParams.append('state', state);

  res.redirect(redirectUrl.toString());
});

app.post('/oauth/token/validate', async (req, res) => {
  try {
    const { access_token } = req.body;
    if (!access_token) {
      return res.status(400).json({ error: 'invalid_request' });
    }

    const tokenData = await redisClient.get(`access:${access_token}`);
    if (!tokenData) {
      return res.status(401).json({ error: 'invalid_token' });
    }

    const data = JSON.parse(tokenData);
    return res.json({
      active: true,
      user_id: data.user_id,
      client_id: data.client_id,
      scopes: data.scopes
    });
  } catch (error) {
    console.error('Validation error:', error);
    res.status(500).json({ error: 'server_error' });
  }
});

